const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

// ===== Data Collection =====

// Service health
const healthData = $('获取服务状态').first().json;
const services = healthData.services || healthData.components || {};
const svcStatus = (name) => {
  const s = services[name]?.status;
  if (s === 'healthy' || s === 'ok') return '\u2705';
  if (healthData.status === 'healthy') return '\u2705';
  return '\u274c';
};

// RSS fetch stats
const rssLogs = $('获取RSS采集详情').first().json.data?.items || [];
const rssSuccess = rssLogs.filter(l => l.status === 'success').length;
const rssFailed = rssLogs.filter(l => l.status === 'failed').length;

// Failed articles detail
const failedArticles = rssLogs
  .filter(l => l.status === 'failed' && l.detail)
  .map(l => {
    try {
      const d = typeof l.detail === 'string' ? JSON.parse(l.detail) : l.detail;
      const articles = d.articles || d.failed || [];
      return articles.map(a => `- [${a.title || 'Untitled'}](${a.url || ''}) - ${a.error || l.summary || ''}`);
    } catch(e) { return []; }
  })
  .flat();

// KB ingestion (from K08)
const kbLogs = $('获取KB入库日志').first().json.data?.items || []; // items filtered by since on server
const kbTodayItems = kbLogs; // server already filters by since
const datasetNames = {
  'd15bd2ac07ae11f1a088ae230b1794d7': '\u6bcf\u65e5\u8baf\u606f',
  'd157b35c07ae11f1a088ae230b1794d7': 'AI\u6280\u672f',
  'd1537f8a07ae11f1a088ae230b1794d7': '\u5f00\u53d1\u6280\u672f',
  'd14f2fac07ae11f1a088ae230b1794d7': '\u7f51\u7edc\u5b89\u5168',
  'd14aaa7c07ae11f1a088ae230b1794d7': '\u5b89\u5168\u6f0f\u6d1e',
};

// Group KB items by dataset
const kbGrouped = {};
let kbTotal = 0;
for (const item of kbTodayItems) {
  const dsId = item.ref_id || '';
  if (!kbGrouped[dsId]) kbGrouped[dsId] = [];
  const m = item.summary?.match(/\u8def\u7531\u4e0a\u4f20 (.+?) \u5230/);
  if (m) {
    const title = m[1].replace(/-+/g,' ').replace(/\.(md|txt)$/i,'').trim();
    kbGrouped[dsId].push(title);
    kbTotal++;
  }
}

const kbSections = []; // [{ dataset: name, titles: [string] }]
for (const [dsId, titles] of Object.entries(kbGrouped)) {
  const name = datasetNames[dsId] || dsId.slice(0,8);
  kbSections.push({ dataset: name, titles });
}

// Article total count
const totalArticles = $('获取文章总数').first().json.pagination?.total || 0;
const datasets = $('获取文章总数').first().json.data?.items || [];
const datasetLines = datasets.map(d => `| ${d.name} | ${d.document_count || 0} \u7bc7 |`);

// Todos
const todoItems = $('获取待办事项').first().json.memos || []; // changed: store full list for detail
const todoCount = todoItems.length;
const todoDetails = todoItems.slice(0, 10).map(m => {
  const content = (m.content || '').replace(/#[^\s]+/g, '').trim();
  return `- ${content}`;
});

// ===== Build AI Prompt =====
// Only call LLM if there are KB articles today
let aiPrompt = '';
if (kbTotal > 0) {
  let promptLines = [`\u4eca\u5929(${dateStr})\u5171\u5165\u5e93 ${kbTotal} \u7bc7\u6587\u7ae0\uff0c\u6309\u9886\u57df\u5206\u7c7b\u5982\u4e0b\uff1a\n`];
  for (const s of kbSections) {
    promptLines.push(`\u3010${s.dataset}\u3011(${s.titles.length}\u7bc7)`);
    for (const t of s.titles.slice(0,20)) promptLines.push(`  - ${t}`);
    if (s.titles.length > 20) promptLines.push(`  ... \u5171${s.titles.length}\u7bc7`);
  }
  promptLines.push('\n\u8bf7\u6309\u9886\u57df\u5206\u522b\u75282-3\u53e5\u8bdd\u6982\u62ec\u4eca\u65e5\u8baf\u606f\u4eae\u70b9\uff0c\u6700\u540e\u7ed9\u51fa\u4e00\u53e5\u603b\u4f53\u8bc4\u4ef7\u3002\u8f93\u51fa\u4e2d\u6587\u3002');
  aiPrompt = promptLines.join('\n');
}

return [{ json: {
  date: dateStr,
  // Health
  healthData,
  svcStatus,
  // RSS
  rssSuccess,
  rssFailed,
  failedArticles,
  // KB
  kbTotal,
  kbSections,
  aiPrompt,
  // Article counts
  totalArticles,
  datasetLines,
  // Todos
  todoCount,
  todoDetails
} }];

// ===== Build Unified Markdown =====

const data = $('整理数据').first().json;
const date = data.date;
const svcStatus = data.svcStatus;

// AI summary (from LLM Proxy, or fallback)
const llmResp = $('调用LLM总结').first().json;
const aiText = llmResp.choices?.[0]?.message?.content
  || llmResp.result
  || llmResp.content
  || '(AI\u4eae\u70b9\u6982\u62ec\u6682\u4e0d\u53ef\u7528)';

let md = `### \ud83d\udcca \u6bcf\u65e5\u77e5\u8bc6\u5e93\u65e5\u62a5 - ${date}\n\n`;

// ===== Section 1: Service Health =====
md += `#### \ud83d\udce6 \u670d\u52a1\u72b6\u6001\n\n`;
md += `| \u670d\u52a1 | \u72b6\u6001 |\n|------|------|\n`;
md += `| Bellkeeper | ${svcStatus('bellkeeper')} |\n`;
md += `| RagFlow | ${svcStatus('ragflow')} |\n`;
md += `| Firecrawl | ${svcStatus('firecrawl')} |\n\n`;

// ===== Section 2: RSS Fetch Stats =====
md += `#### \ud83d\udce5 \u4eca\u65e5\u5185\u5bb9\u91c7\u96c6\n\n`;
if (data.rssSuccess > 0 || data.rssFailed > 0) {
  md += `| \u6307\u6807 | \u6570\u91cf |\n|------|------|\n`;
  md += `| \u6210\u529f\u5165\u5e93 | ${data.rssSuccess} \u7bc7 |\n`;
  md += `| \u5931\u8d25 | ${data.rssFailed} \u7bc7 |\n\n`;
  if (data.failedArticles && data.failedArticles.length > 0) {
    md += `**\u5931\u8d25\u6587\u7ae0:**\n\n`;
    md += data.failedArticles.join('\n') + '\n\n';
  }
} else {
  md += `*\u4eca\u65e5\u65e0 RSS \u91c7\u96c6\u8bb0\u5f55*\n\n`;
}

// ===== Section 3: KB Ingestion Stats (from K08) =====
md += `#### \ud83d\udcda \u77e5\u8bc6\u5e93\u5165\u5e93\u7edf\u8ba1\n\n`;
if (data.kbTotal > 0) {
  md += `\u4eca\u65e5\u5165\u5e93 **${data.kbTotal} \u7bc7**\u6587\u7ae0\n\n`;
  md += `| \u9886\u57df | \u6587\u7ae0\u6570 |\n|------|---------|\n`;
  for (const s of data.kbSections) {
    md += `| ${s.dataset} | ${s.titles.length} \u7bc7 |\n`;
  }
  md += '\n';
} else {
  md += `*\u4eca\u65e5\u65e0\u5165\u5e93\u8bb0\u5f55*\n\n`;
}

// ===== Section 4: AI Highlights (from K08, via LLM Proxy) =====
md += `#### \ud83e\udd16 AI \u4eae\u70b9\u603b\u7ed3\n\n`;
md += aiText + '\n\n';

// ===== Section 5: Article Total Counts =====
md += `#### \ud83d\udcc8 \u77e5\u8bc6\u5e93\u7edf\u8ba1\n\n`;
md += `- **\u6587\u7ae0\u603b\u6570**: ${data.totalArticles} \u7bc7\n\n`;
if (data.datasetLines && data.datasetLines.length > 0) {
  md += `| \u6570\u636e\u96c6 | \u6587\u7ae0\u6570 |\n|---------|---------|\n`;
  md += data.datasetLines.join('\n') + '\n\n';
}

// ===== Section 6: Todo Items =====
md += `#### \ud83d\udcdd \u5f85\u529e\u4e8b\u9879\n\n`;
md += `- \u672a\u5b8c\u6210: ${data.todoCount} \u9879`;
if (data.todoDetails && data.todoDetails.length > 0) {
  md += '\n\n' + data.todoDetails.join('\n');
}

return [{ json: { room: 'daily', markdown: md, date: date } }];
